+fn shell_escape(argument: &str) -> String {
+    if argument.is_empty() {
+        return "''".to_string();
+    }
+
+    if argument
+        .bytes()
+        .all(|byte| byte.is_ascii_alphanumeric() || b"-_./:=+".contains(&byte))
+    {
+        return argument.to_string();
+    }
+
+    format!("'{}'", argument.replace('\'', "'\"'\"'"))
